import{_ as a,o as e,c as l,a2 as o}from"./chunks/framework.BQ1gajhD.js";const h=JSON.parse('{"title":"谐趣园","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/summer-palace/xiequ-yuan.md","filePath":"landmarks/summer-palace/xiequ-yuan.md","lastUpdated":1784720050000}'),r={name:"landmarks/summer-palace/xiequ-yuan.md"};function n(s,t,i,d,u,q){return e(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="谐趣园" tabindex="-1">谐趣园 <a class="header-anchor" href="#谐趣园" aria-label="Permalink to &quot;谐趣园&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1762663983944-9acb89c68650?w=1200&amp;q=80" alt="谐趣园"></p><blockquote><p>&quot;通常拟惠山，肖之为惠山园。&quot; —— 乾隆御诗道出这座&quot;园中之园&quot;的身世</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>谐趣园位于颐和园东北角、后湖东端，是一座藏于大园之中的小园，素有&quot;园中之园&quot;的美誉。它仿无锡名园寄畅园而建，小巧精致，自成天地：一池碧水居中，亭台楼阁环池而筑，游廊曲折相接，假山点缀其间，虽处北方皇家园林之中，却尽显江南私家园林的婉约气韵。</p><p>从万寿山的巍峨排场走进谐趣园的曲径回廊，恍如从庙堂退入山林，呼吸都为之一缓。</p><p>谐趣园始建于乾隆十六年（1751年）。乾隆首次南巡时驻跸无锡寄畅园，对其&quot;山水清音&quot;一见倾心，回京后便命画师携图仿建，初名&quot;惠山园&quot;，取&quot;惠山&quot;之音。嘉庆十六年（1811年）重修后更名&quot;谐趣园&quot;，寓&quot;以物外之静趣，谐寸田之中和&quot;之意——游目骋怀，心与物谐，正是这座小园的精神内核。1860年谐趣园同样毁于英法联军大火，现存建筑为光绪年间依原样重建。</p><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年代</th><th style="text-align:left;">大事</th></tr></thead><tbody><tr><td style="text-align:left;">清乾隆十六年（1751）</td><td style="text-align:left;">首次南巡后仿无锡寄畅园始建，名&quot;惠山园&quot;</td></tr><tr><td style="text-align:left;">嘉庆十六年（1811）</td><td style="text-align:left;">重修，更名&quot;谐趣园&quot;</td></tr><tr><td style="text-align:left;">咸丰十年（1860）</td><td style="text-align:left;">遭英法联军焚毁</td></tr><tr><td style="text-align:left;">清光绪年间</td><td style="text-align:left;">依原样重建，格局一仍其旧</td></tr><tr><td style="text-align:left;">当代</td><td style="text-align:left;">免费开放（含于大门票），颐和园最清静的去处</td></tr></tbody></table><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>格局</strong></td><td style="text-align:left;">以水池为中心，环池布置亭台楼阁、游廊假山</td></tr><tr><td style="text-align:left;"><strong>涵远堂</strong></td><td style="text-align:left;">园中正殿，面阔五间，帝后游园休憩之所</td></tr><tr><td style="text-align:left;"><strong>知鱼桥</strong></td><td style="text-align:left;">贴水低桥，典出《庄子》&quot;濠梁之辩&quot;</td></tr><tr><td style="text-align:left;"><strong>瞩新楼</strong></td><td style="text-align:left;">两层小楼，登楼可俯瞰全园</td></tr><tr><td style="text-align:left;"><strong>澄爽斋</strong></td><td style="text-align:left;">临水而筑，推窗即见荷风</td></tr><tr><td style="text-align:left;"><strong>其他</strong></td><td style="text-align:left;">引镜、洗秋、饮绿诸亭榭，环池游廊嵌书法石刻</td></tr></tbody></table><p>谐趣园以一方水池为核心，四周建筑皆面水而立：北岸涵远堂为园中正殿，面阔五间；西岸瞩新楼两层，登楼可俯瞰全园；南岸澄爽斋临水而筑，推窗即见荷风送香。环池游廊将诸建筑连为一体，廊壁嵌有历代书法石刻。</p><p>最妙的是那座贴水而建的知鱼桥——桥身极低，几乎与水面相平，人行桥上如在鱼背，俯身即见游鱼往来。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="知鱼桥上的-濠梁之辩" tabindex="-1">知鱼桥上的&quot;濠梁之辩&quot; <a class="header-anchor" href="#知鱼桥上的-濠梁之辩" aria-label="Permalink to &quot;知鱼桥上的&quot;濠梁之辩&quot;&quot;">​</a></h3><p>谐趣园最出名的小景是知鱼桥。桥名典出《庄子·秋水》：庄子与惠子游于濠梁之上，庄子曰：&quot;鲦鱼出游从容，是鱼之乐也。&quot;惠子反问：&quot;子非鱼，安知鱼之乐？&quot;庄子答：&quot;子非我，安知我不知鱼之乐？&quot;</p><p>乾隆对此典故极为偏爱，不仅将桥命名为&quot;知鱼&quot;，还在桥头题诗：&quot;鱼跃鸢飞同活泼，水流山静共悠然。&quot;如今桥栏低矮，游鱼不惧人，春夏之交柳丝拂水、鱼群唼喋，站在桥上发呆十分钟，便能明白这座园子为何叫&quot;谐趣&quot;——不必真的知道鱼乐不乐，此刻你自己是快乐的，就够了。</p><h3 id="乾隆的-园林搬运术" tabindex="-1">乾隆的&quot;园林搬运术&quot; <a class="header-anchor" href="#乾隆的-园林搬运术" aria-label="Permalink to &quot;乾隆的&quot;园林搬运术&quot;&quot;">​</a></h3><p>乾隆一生六下江南，每到一处名园必令随行画师绘图摹样，回京后择地仿建：仿海宁安澜园、仿苏州狮子林、仿南京瞻园，谐趣园仿的则是无锡寄畅园。这种&quot;移天缩地&quot;的做法，让三山五园集江南名园之大成。</p><p>有趣的是，寄畅园借景锡山龙光塔，谐趣园则借景万寿山余脉——仿的是格局，变的是气韵，北方山水给了这座&quot;无锡分园&quot;一副更开阔的骨架。</p><h3 id="一园之内-四种造园法" tabindex="-1">一园之内，四种造园法 <a class="header-anchor" href="#一园之内-四种造园法" aria-label="Permalink to &quot;一园之内，四种造园法&quot;">​</a></h3><p>谐趣园虽小，却是中国造园技法的微缩教材：<strong>障景</strong>——入园先以假山、照壁挡眼，逼你转过弯才见全池；<strong>框景</strong>——游廊花窗把池柳亭台裁成一幅幅册页；<strong>对景</strong>——涵远堂与瞩新楼隔水相望，互为观赏对象；<strong>借景</strong>——抬头处万寿山余脉入园作背景。300米方圆之内走完这四种手法，等于上了一堂园林课。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>知鱼桥</strong>：贴水低桥，俯身观鱼，体会庄子&quot;濠梁之辩&quot;的哲学趣味，是全园最不容错过的一景。</li><li><strong>涵远堂</strong>：园中正殿，殿前平台临水，是观赏全园倒影的最佳位置，雨日听荷尤佳。</li><li><strong>环池游廊</strong>：廊壁书法石刻与框景窗格交替出现，一步一景，尽显江南园林的曲折含蓄。</li><li><strong>瞩新楼</strong>：两层小楼为全园制高点，登楼俯瞰，水池、亭台、假山尽收一池之小。</li><li><strong>四季小景</strong>：春看柳、夏赏荷、秋听雨、冬观雪——小园的好处在于，任何时候来都有独属此刻的意境。</li></ol><h2 id="拍照机位" tabindex="-1">拍照机位 <a class="header-anchor" href="#拍照机位" aria-label="Permalink to &quot;拍照机位&quot;">​</a></h2><ol><li><strong>知鱼桥俯拍</strong>：低机位贴水面拍游鱼与桥影，春夏柳丝入镜最佳。</li><li><strong>涵远堂前平台</strong>：隔水拍对岸瞩新楼与全园倒影，无风时如镜面。</li><li><strong>花窗框景</strong>：游廊漏窗框出的一角池景，是现成的&quot;宋画&quot;构图。</li></ol><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ol><li>谐趣园免费开放（含在大门票内），无需另购票，是颐和园中性价比极高的清净去处。</li><li>位置偏居东北角，多数旅行团不涉足，想避开人潮的独行客首选此地，尤其清晨和黄昏。</li><li>建议从后湖东端进入，与<a href="/beijing-travel-guide/landmarks/summer-palace/suzhou-street.html">苏州街</a>串联游览，后山一线清幽，与前山喧闹判若两园。</li><li>若对无锡寄畅园感兴趣，不妨将两处&quot;对照游&quot;：同一种造园语言，在江南与京畿各自生长出不同的气质。</li><li>园内游廊低矮、石径湿滑，雨后参观注意脚下；带孩子的游客在知鱼桥观鱼时务必看护好孩童。</li><li>逛完谐趣园从园东小门出，即是东宫门方向，可接续<a href="/beijing-travel-guide/landmarks/summer-palace/renshou-dian.html">仁寿殿</a>的行程。</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q：谐趣园需要买票吗？</strong></p><p>不需要。谐趣园包含在颐和园大门票内，免费进入，是全园性价比最高的景点之一。</p><p><strong>Q：谐趣园和无锡寄畅园哪个更值得看？</strong></p><p>各擅胜场：寄畅园是江南原生的私家园林，山水更苍古；谐趣园是皇家手笔的&quot;北方版&quot;，尺度更疏朗。时间允许，两处对照着看最有意思。</p><p><strong>Q：谐趣园为什么人少？</strong></p><p>位置偏在颐和园东北角，旅行团的大巴从北宫门、东宫门进出，很少绕到这里——这正是它最大的优点。</p><p><strong>Q：谐趣园什么时候去最美？</strong></p><p>夏看荷、冬看雪；行家里手更推荐雨天的涵远堂——隔水听雨打荷叶，才是这座园子名字里那个&quot;趣&quot;字。</p><hr><p><strong>📍 位置</strong>：颐和园东北角，后湖东端 <strong>⏱️ 建议游览</strong>：30-40分钟 <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/summer-palace/">颐和园概览</a></p>',39)])])}const p=a(r,[["render",n]]);export{h as __pageData,p as default};
